+// FD returns the file descriptor for passing to other processes.
+func (sc *SharedCounter) FD() int {
+	return sc.fd
+}
+
+// Increment atomically increments the counter and returns the new value.
+func (sc *SharedCounter) Increment() uint64 {
+	ptr := (*uint64)(unsafe.Pointer(&sc.data[0]))
+	return atomic.AddUint64(ptr, 1)
+}
+
+// Read atomically reads the current counter value.
+func (sc *SharedCounter) Read() uint64 {
+	ptr := (*uint64)(unsafe.Pointer(&sc.data[0]))
+	return atomic.LoadUint64(ptr)
+}
+
+// Close unmaps and closes the file descriptor.
+func (sc *SharedCounter) Close() error {
+	if sc.data != nil {
+		if err := syscall.Munmap((*[1<<30]byte)(unsafe.Pointer(&sc.data[0]))[:counterSize]); err != nil {
+			return fmt.Errorf("munmap: %w", err)
+		}
+		sc.data = nil
+	}
+	if sc.fd >= 0 {
+		if err := os.NewFile(uintptr(sc.fd), "").Close(); err != nil {
+			return fmt.Errorf("close fd: %w", err)
+		}
+		sc.fd = -1
+	}
+	return nil
+}
