+package shm
+
+import (
+	"os"
+	"testing"
+)
+
+func TestNewSharedCounter(t *testing.T) {
+	sc, err := NewSharedCounter(42)
+	if err != nil {
+		t.Fatalf("NewSharedCounter failed: %v", err)
+	}
+	defer sc.Close()
+
+	if v := sc.Read(); v != 42 {
+		t.Fatalf("expected initial 42, got %d", v)
+	}
+
+	newVal := sc.Increment()
+	if newVal != 43 {
+		t.Fatalf("expected incremented 43, got %d", newVal)
+	}
+	if v := sc.Read(); v != 43 {
+		t.Fatalf("expected final 43, got %d", v)
+	}
+}
+
+func TestAttachViaDup(t *testing.T) {
+	sc, err := NewSharedCounter(0)
+	if err != nil {
+		t.Fatalf("NewSharedCounter: %v", err)
+	}
+	defer sc.Close()
+
+	// Duplicate the FD to simulate FD passing (dup2).
+	newFd, err := syscall.Dup(sc.FD())
+	if err != nil {
+		t.Fatalf("dup: %v", err)
+	}
+	// Attach using the new FD.
+	sc2, err := AttachSharedCounter(newFd)
+	if err != nil {
+		t.Fatalf("AttachSharedCounter: %v", err)
+	}
+	defer sc2.Close()
+
+	// Increment via original.
+	sc.Increment()
+	// Read via attached.
+	if v := sc2.Read(); v != 1 {
+		t.Fatalf("expected 1 via attached, got %d", v)
+	}
+	// Increment via attached.
+	sc2.Increment()
+	if v := sc.Read(); v != 2 {
+		t.Fatalf("expected 2 via original, got %d", v)
+	}
+}
