+import "github.com/yourorg/aortctl/internal/ipc/shm"
+
+// evidenceCounter is the global shared evidence counter.
+var evidenceCounter *shm.SharedCounter
+
+// CreateSharedEvidenceCounter creates a new shared evidence counter and returns its FD.
+// The counter is initialized to 0.
+func CreateSharedEvidenceCounter() (int, error) {
+	var err error
+	evidenceCounter, err = shm.NewSharedCounter(0)
+	if err != nil {
+		return -1, err
+	}
+	return evidenceCounter.FD(), nil
+}
+
+// AttachSharedEvidenceCounter attaches to a shared evidence counter via the given FD.
+// It increments the counter to signal that context has been received.
+func AttachSharedEvidenceCounter(fd int) error {
+	var err error
+	evidenceCounter, err = shm.AttachSharedCounter(fd)
+	if err != nil {
+		return err
+	}
+	evidenceCounter.Increment()
+	return nil
+}
+
+// EvidenceRead returns the current evidence counter value.
+func EvidenceRead() uint64 {
+	if evidenceCounter == nil {
+		return 0
+	}
+	return evidenceCounter.Read()
+}
